import React, { useState, useEffect } from "react";
import axios from "axios";

const BlogManage = () => {
  const [blogs, setBlogs] = useState([]);
  const [form, setForm] = useState({
    title: "",
    content: "",
    full_content: "",
    image_url: "",
    user_id: 1,
    category_id: 1,
  });
  const [editId, setEditId] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const fetchBlogs = async () => {
    try {
      setLoading(true);
      const res = await axios.get("http://localhost:5000/api/blogs");
      setBlogs(res.data);
      setLoading(false);
    } catch (err) {
      console.error("Error fetching blogs", err);
      setError("Failed to fetch blogs.");
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchBlogs();
  }, []);

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");
    console.log(editId ? "Updating blog" : "Adding blog", form);

    try {
      setLoading(true);
      if (editId) {
        await axios.put(`http://localhost:5000/api/blogs/${editId}`, form);
        setEditId(null);
      } else {
        await axios.post("http://localhost:5000/api/blogs", form);
      }
      setForm({
        title: "",
        content: "",
        full_content: "",
        image_url: "",
        user_id: 1,
        category_id: 1,
      });
      await fetchBlogs();
      setLoading(false);
    } catch (err) {
      console.error("Error saving blog", err);
      setError("Failed to save blog. Please check console.");
      setLoading(false);
    }
  };

  const handleEdit = (blog) => {
    console.log("Editing blog:", blog);
    setForm({
      title: blog.title,
      content: blog.content,
      full_content: blog.full_content,
      image_url: blog.image_url || "",
      user_id: blog.user_id,
      category_id: blog.category_id,
    });
    setEditId(blog.id);
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Delete this blog?")) return;
    try {
      setLoading(true);
      await axios.delete(`http://localhost:5000/api/blogs/${id}`);
      await fetchBlogs();
      setLoading(false);
    } catch (err) {
      console.error("Error deleting blog", err);
      setError("Failed to delete blog.");
      setLoading(false);
    }
  };

  return (
    <div>
      <h2 className="text-xl font-bold mb-4">
        {editId ? "Edit Blog" : "Add Blog"}
      </h2>

      {error && (
        <p className="mb-4 text-red-600 font-semibold">
          {error}
        </p>
      )}

      <form onSubmit={handleSubmit} className="mb-6 space-y-3">
        <input
          name="title"
          value={form.title}
          onChange={handleChange}
          placeholder="Title"
          className="p-2 border rounded w-full"
          required
        />
        <textarea
          name="content"
          value={form.content}
          onChange={handleChange}
          placeholder="Short preview content"
          className="p-2 border rounded w-full"
          required
        />
        <textarea
          name="full_content"
          value={form.full_content}
          onChange={handleChange}
          placeholder="Full detailed content"
          className="p-2 border rounded w-full"
          required
        />
        <input
          name="image_url"
          value={form.image_url}
          onChange={handleChange}
          placeholder="Image URL"
          className="p-2 border rounded w-full"
        />
        <input
          type="number"
          name="user_id"
          value={form.user_id}
          onChange={handleChange}
          placeholder="User ID"
          className="p-2 border rounded w-full"
          required
          min={1}
        />
        <input
          type="number"
          name="category_id"
          value={form.category_id}
          onChange={handleChange}
          placeholder="Category ID"
          className="p-2 border rounded w-full"
          required
          min={1}
        />
        <button
          type="submit"
          disabled={loading}
          className={`px-4 py-2 rounded text-white ${
            loading ? "bg-gray-400 cursor-not-allowed" : "bg-green-600 hover:bg-green-700"
          }`}
        >
          {editId ? "Update Blog" : "Add Blog"}
        </button>
      </form>

      {loading && <p>Loading blogs...</p>}

      <table className="w-full table-auto border border-gray-300 bg-white">
        <thead>
          <tr className="bg-gray-200">
            <th className="p-2 border">ID</th>
            <th className="p-2 border">Title</th>
            <th className="p-2 border">Category</th>
            <th className="p-2 border">Actions</th>
          </tr>
        </thead>
        <tbody>
          {blogs.map((blog) => (
            <tr key={blog.id}>
              <td className="p-2 border text-center">{blog.id}</td>
              <td className="p-2 border">{blog.title}</td>
              <td className="p-2 border text-center">{blog.category_id}</td>
              <td className="p-2 border text-center space-x-2">
                <button
                  onClick={() => handleEdit(blog)}
                  className="bg-blue-500 text-white px-2 py-1 rounded"
                >
                  Edit
                </button>
                <button
                  onClick={() => handleDelete(blog.id)}
                  className="bg-red-500 text-white px-2 py-1 rounded"
                >
                  Delete
                </button>
              </td>
            </tr>
          ))}
          {blogs.length === 0 && !loading && (
            <tr>
              <td colSpan={4} className="text-center p-4">
                No blogs found.
              </td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
};

export default BlogManage;
